module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);


wire [7:0] mul_a_ext, mul_b_ext;
wire [7:0] partial_product_0, partial_product_1, partial_product_2, partial_product_3;
reg [7:0] sum_tmp1, sum_tmp2;
reg [7:0] mul_out_reg;

assign mul_a_ext = {{size{1'b0}}, mul_a};
assign mul_b_ext = {{size{1'b0}}, mul_b};

assign partial_product_0 = (mul_b[0]) ? mul_a_ext : 'd0;
assign partial_product_1 = (mul_b[1]) ? mul_a_ext << 1 : 'd0;
assign partial_product_2 = (mul_b[2]) ? mul_a_ext << 2 : 'd0;
assign partial_product_3 = (mul_b[3]) ? mul_a_ext << 3 : 'd0;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        sum_tmp1 <= 'd0;
        sum_tmp2 <= 'd0;
    end else begin
        sum_tmp1 <= partial_product_0 + partial_product_1;
        sum_tmp2 <= partial_product_2 + partial_product_3;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        mul_out_reg <= 'd0;
    end else begin
        mul_out_reg <= sum_tmp1 + sum_tmp2;
    end
end

assign mul_out = mul_out_reg;
endmodule
